 11→class CallbackFlowTest : TestBase() {
 12→
 13→    private class CallbackApi(val block: (SendChannel<Int>) -> Unit) {
 14→        var started = false
 15→        @Volatile
 16→        var stopped = false
 17→        lateinit var thread: Thread
 18→
 19→        fun start(sink: SendChannel<Int>) {
 20→            started = true
 21→            thread = thread {
 22→                while (!stopped) {
 23→                    block(sink)
 24→                }
 25→            }
 26→        }
 27→
 28→        fun stop() {
 29→            stopped = true
 30→        }
 31→    }
 32→
 33→    @Test(timeout = 5_000L)
 34→    fun testThrowingConsumer() = runTest {
 35→        var i = 0
 36→        val api = CallbackApi {
 37→            it.trySend(++i)
 38→        }
 39→
 40→        val flow = callbackFlow<Int> {
 41→            api.start(channel)
 42→            awaitClose {
 43→                api.stop()
 44→            }
 45→        }
 46→
 47→        var receivedConsensus = 0
 48→        var isDone = false
 49→        var exception: Throwable? = null
 50→        val job = flow
 51→            .filter { it > 10 }
 52→            .launchIn(this) {
 53→                onEach {
 54→                    if (it == 11) {
 55→                        ++receivedConsensus
 56→                    } else {
 57→                        receivedConsensus = 42
 58→                    }
 59→                    throw RuntimeException()
 60→                }
 61→                catch<Throwable> { exception = it }
 62→                finally { isDone = true }
 63→            }
 64→        job.join()
 65→        assertEquals(1, receivedConsensus)
 66→        assertTrue(isDone)
 67→        assertTrue { exception is RuntimeException }
 68→        api.thread.join()
 69→        assertTrue(api.started)
 70→        assertTrue(api.stopped)
 71→    }
 72→
 73→    @Test(timeout = 5_000L)
 74→    fun testThrowingSource() = runBlocking {
 75→        var i = 0
 76→        val api = CallbackApi {
 77→            if (i < 5) {
 78→                it.trySend(++i)
 79→            } else {
 80→                it.close(RuntimeException())
 81→            }
 82→        }
 83→
 84→        val flow = callbackFlow<Int> {
 85→            api.start(channel)
 86→            awaitClose {
 87→                api.stop()
 88→            }
 89→        }
 90→
 91→        var received = 0
 92→        var isDone = false
 93→        var exception: Throwable? = null
 94→        val job = flow.launchIn(this) {
 95→            onEach { ++received }
 96→            catch<Throwable> { exception = it }
 97→            finally { isDone = true }
 98→        }
 99→
100→        job.join()
101→        assertTrue(isDone)
102→        assertTrue { exception is RuntimeException }
103→        api.thread.join()
104→        assertTrue(api.started)
105→        assertTrue(api.stopped)
106→    }
107→
108→
109→    @Test
110→    fun testMergeExample() = runTest {
111→        // Too slow on JS
112→        withContext(Dispatchers.Default) {
113→            val f1 = (1..10_000).asFlow()
114→            val f2 = (10_001..20_000).asFlow()
115→            assertEquals((1..20_000).toSet(), f1.merge(f2).toSet())
116→        }
117→    }
118→
119→    private fun Flow<Int>.merge(other: Flow<Int>): Flow<Int> = channelFlow {
120→        launch {
121→            collect { send(it) }
122→        }
123→        other.collect { send(it) }
124→    }
125→}
